const query = $json.query || {};
const topic = query.topic || null;
const source = query.source || null;
const page = parseInt(query.page) || 1;
const limit = Math.min(parseInt(query.limit) || 20, 50);
const search = query.search || null;
const offset = (page - 1) * limit;

const AGE_CLAUSE = "AND a.published_at > NOW() - INTERVAL 7 DAY";
const sourceWhere = source ? ` AND s.name = '${source.replace(/'/g, "''")}'` : '';
const SELECT_COLS = "a.id, a.title, a.url, a.author, a.published_at, a.ai_summary, a.ai_tags, a.relevance_score, a.topic, a.content_snippet, s.name as source_name, s.source_type";

let sql, countSql;

if (search) {
  // Search: existing behavior (sort by relevance + recency, no per-source cap).
  const searchEsc = search.replace(/'/g, "''");
  const topicWhere = topic ? ` AND a.topic = '${topic.replace(/'/g, "''")}'` : '';
  sql = `SELECT ${SELECT_COLS} FROM news_articles a JOIN news_sources s ON a.source_id = s.id WHERE MATCH(a.title, a.ai_summary, a.content_snippet) AGAINST('${searchEsc}' IN NATURAL LANGUAGE MODE)${topicWhere}${sourceWhere} ${AGE_CLAUSE} ORDER BY a.relevance_score DESC, a.published_at DESC LIMIT ${limit} OFFSET ${offset}`;
  countSql = `SELECT COUNT(*) AS total FROM news_articles a JOIN news_sources s ON a.source_id = s.id WHERE MATCH(a.title, a.ai_summary, a.content_snippet) AGAINST('${searchEsc}' IN NATURAL LANGUAGE MODE)${topicWhere}${sourceWhere} ${AGE_CLAUSE}`;
} else if (topic === 'ai' && !source) {
  // AI tab default: diversify by capping each source to 5 items per pool.
  // The pool is then re-sorted by relevance + recency so high-scoring
  // articles still bubble up, but no single source can flood the first page.
  const PER_SOURCE_CAP = 5;
  sql = `SELECT * FROM (
    SELECT ${SELECT_COLS},
           ROW_NUMBER() OVER (PARTITION BY a.source_id ORDER BY a.relevance_score DESC, a.published_at DESC) AS rn
    FROM news_articles a
    JOIN news_sources s ON a.source_id = s.id
    WHERE a.topic = 'ai' AND a.relevance_score >= 5 ${AGE_CLAUSE}
  ) capped
  WHERE rn <= ${PER_SOURCE_CAP}
  ORDER BY relevance_score DESC, published_at DESC
  LIMIT ${limit} OFFSET ${offset}`;
  countSql = `SELECT COUNT(*) AS total FROM (
    SELECT 1 FROM (
      SELECT a.id, ROW_NUMBER() OVER (PARTITION BY a.source_id ORDER BY a.relevance_score DESC, a.published_at DESC) AS rn
      FROM news_articles a
      JOIN news_sources s ON a.source_id = s.id
      WHERE a.topic = 'ai' AND a.relevance_score >= 5 ${AGE_CLAUSE}
    ) capped WHERE rn <= ${PER_SOURCE_CAP}
  ) c`;
} else {
  // Other topics + explicit source filter: simple recency or relevance sort.
  const topicWhere = topic ? `AND a.topic = '${topic.replace(/'/g, "''")}'` : '';
  const orderClause = topic === 'ai'
    ? 'ORDER BY a.relevance_score DESC, a.published_at DESC'
    : 'ORDER BY a.published_at DESC, a.relevance_score DESC';
  sql = `SELECT ${SELECT_COLS} FROM news_articles a JOIN news_sources s ON a.source_id = s.id WHERE 1=1 ${topicWhere}${sourceWhere} AND a.relevance_score >= 5 ${AGE_CLAUSE} ${orderClause} LIMIT ${limit} OFFSET ${offset}`;
  countSql = `SELECT COUNT(*) AS total FROM news_articles a JOIN news_sources s ON a.source_id = s.id WHERE 1=1 ${topicWhere}${sourceWhere} AND a.relevance_score >= 5 ${AGE_CLAUSE}`;
}

return [{ json: { sql, countSql, page, limit } }];

const articles = $('Query Articles').all().map(i => {
  const a = i.json;
  let tags = a.ai_tags;
  if (typeof tags === 'string') {
    try { tags = JSON.parse(tags); } catch(e) { tags = []; }
  }
  return { ...a, ai_tags: tags || [] };
});

const meta = $('Build Query').first().json;
const countRow = $input.first()?.json || {};
const total = Number(countRow.total ?? countRow['COUNT(*)'] ?? articles.length) || articles.length;

return [{ json: { articles, total, page: meta.page } }];

const body = $json.body || {};
const message = body.message || '';
const sessionId = body.session_id || 'default';

// Escape for SQL
const esc = (v) => v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : "''";

// Build the article search query using FULLTEXT
const searchTerms = message.replace(/['"]/g, '').substring(0, 200);
const searchSql = `SELECT a.id, a.title, a.url, a.ai_summary, a.content_snippet, a.topic, a.published_at, s.name as source_name FROM news_articles a JOIN news_sources s ON a.source_id = s.id WHERE MATCH(a.title, a.ai_summary, a.content_snippet) AGAINST(${esc(searchTerms)} IN NATURAL LANGUAGE MODE) ORDER BY a.published_at DESC LIMIT 10`;

// Save user message
const saveSql = `INSERT INTO news_chat_history (session_id, role, message) VALUES (${esc(sessionId)}, 'user', ${esc(message)})`;

// Get recent chat history
const historySql = `SELECT role, message FROM news_chat_history WHERE session_id = ${esc(sessionId)} ORDER BY created_at DESC LIMIT 10`;

return [{ json: { message, sessionId, searchSql, saveSql, historySql } }];

const articles = $input.all().map(i => i.json).filter(a => a.title);
const userMessage = $('Chat Prep').first().json.message;

let context = '';
const sources = [];
if (articles.length > 0) {
  context = '\n\nRelevant articles from our news archive:\n' + 
    articles.map((a, i) => {
      sources.push({ title: a.title, url: a.url });
      return `[${i+1}] "${a.title}" (${a.source_name}, ${a.published_at || 'recent'})\n${a.ai_summary || a.content_snippet || 'No summary available'}`;
    }).join('\n\n');
}

const systemPrompt = `You are a helpful news research assistant. You answer questions about recent news in AI, technology, music production, and computing.

When answering:
- Be concise and informative (2-4 paragraphs max)
- Reference specific articles by their number [1], [2], etc.
- If the archived articles don't cover the question well, say so
- Focus on facts from the articles provided

${context}`;

const requestBody = {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ],
  temperature: 0.5,
  max_tokens: 800
};

return [{ json: { requestBody: JSON.stringify(requestBody), sources } }];

const aiResponse = $json;
const reply = aiResponse?.choices?.[0]?.message?.content || 'I could not generate a response.';
const sources = $('Build AI Request').first().json.sources || [];
const sessionId = $('Chat Prep').first().json.sessionId;

// Escape for SQL
const esc = (v) => v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : "''";
const saveSql = `INSERT INTO news_chat_history (session_id, role, message) VALUES (${esc(sessionId)}, 'assistant', ${esc(reply)})`;

return [{ json: { reply, sources, searched_web: false, saveSql } }];

const body = $json.body || {};
const articleId = parseInt(body.article_id);
const action = body.action || 'save'; // 'save' or 'unsave'

if (!articleId) return [{ json: { error: 'article_id required' } }];

let sql;
if (action === 'unsave') {
  sql = `DELETE FROM news_saved_articles WHERE article_id = ${articleId}`;
} else {
  sql = `INSERT IGNORE INTO news_saved_articles (article_id) VALUES (${articleId})`;
}

return [{ json: { sql, articleId, action } }];

const query = $json.query || {};
const topic = query.topic || null;
const topicWhere = topic ? `AND a.topic = '${topic.replace(/'/g, "''")}'` : '';

const sql = `SELECT a.id, a.title, a.url, a.author, a.published_at, a.ai_summary, a.ai_tags, a.relevance_score, a.topic, a.content_snippet, s.name as source_name, s.source_type, sv.saved_at
FROM news_saved_articles sv
JOIN news_articles a ON sv.article_id = a.id
JOIN news_sources s ON a.source_id = s.id
WHERE 1=1 ${topicWhere}
ORDER BY sv.saved_at DESC`;

return [{ json: { sql } }];

const articles = $input.all().map(i => {
  const a = i.json;
  let tags = a.ai_tags;
  if (typeof tags === 'string') { try { tags = JSON.parse(tags); } catch(e) { tags = []; } }
  return { ...a, ai_tags: tags || [] };
});
return [{ json: { articles, total: articles.length } }];
